#!/usr/bin/env python3 """Drain state/grok-inbox.json run Hermes for queued work, report to Lane C.""" from __future__ import annotations import argparse import json import re import subprocess import sys import time import urllib.error import urllib.request from datetime import datetime, timezone from pathlib import Path ROOT = Path(r"D:\HermesData") INBOX_FILE = ROOT / "state" / "grok-inbox.json" CONFIG_FILE = ROOT / "state" / "grok-direct-discord.json" STATE_FILE = ROOT / "state" / "grok-inbox-consumer.json" DRAIN_LOCK = ROOT / "state" / "grok-inbox-drain.lock" VENV = ROOT / "hermes-agent" / "venv" / "Scripts" / "python.exe" AGENT_LOG = ROOT / "logs" / "agent.log" PROXY_RESTART = ROOT / "scripts" / "Start-Sovereign-Proxy-8091.ps1" GATEWAY = "http://127.0.0.1:8642/v1/chat/completions" MODEL = "phronesis-sovereign-auto" DISCORD_API = "https://discord.com/api/v10" PRIORITY_ORDER = {"P0": 0, "P1": 1, "P2": 2} MAX_RETRIES = 2 MAX_DRAIN = 5 CONSUMER_SYSTEM = ( "Grok-inbox consumer Jeff mobile command via Grok Build (NOT roleplay). Platform=api_server.\n" "Execute with REAL tool_calls only. tool_choice is required.\n" "FORBIDDEN: image_generate, roleplay, OOC narration, narrated JSON, web_extract, guessing paths.\n" "REQUIRED: read_file on exact D:\\ paths given, then write_file or terminal with evidence.\n" "Reply ONLY: list paths read/written + one-line outcome." ) RETRY_SUFFIX = ( "\n\n[RETRY prior turn had tool_turns=0]\n" "Call read_file on the first path in the task. Do NOT narrate tools.\n" "If proxy stale: still attempt read_file on D:\\PhronesisVault\\docs\\agent-coordination\\GROK-HERMES-MASTER-PLAN.md" ) def _utc_now() -> str: return datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ") def _load_json(path: Path, default: dict) -> dict: if not path.is_file(): return dict(default) try: data = json.loads(path.read_text(encoding="utf-8-sig")) return data if isinstance(data, dict) else dict(default) except Exception: return dict(default) def _save_json(path: Path, data: dict) -> None: path.parent.mkdir(parents=True, exist_ok=True) path.write_text(json.dumps(data, indent=2), encoding="utf-8") def _load_env() -> None: sys.path.insert(0, str(ROOT / "scripts")) from phronesis_env import bootstrap_env bootstrap_env() def _api_key() -> str: sys.path.insert(0, str(ROOT / "hermes-agent")) from hermes_cli.config import get_env_value key = (get_env_value("API_SERVER_KEY") or "").strip() if key: return key.split(" #", 1)[0].strip() for line in (ROOT / ".env").read_text(encoding="utf-8").splitlines(): if line.startswith("API_SERVER_KEY="): return line.split("=", 1)[1].strip().split(" #", 1)[0].strip() raise RuntimeError("API_SERVER_KEY missing") def stack_green() -> bool: for url in ( "http://127.0.0.1:8091/health", "http://127.0.0.1:8642/health", "http://127.0.0.1:8090/health", ): try: with urllib.request.urlopen(url, timeout=5) as resp: if resp.status != 200: return False except Exception: return False return True def inference_queue_allows_background() -> tuple[bool, str]: """Defer inbox work while roleplay or deep FIFO pressure owns the GPU.""" try: sys.path.insert(0, str(ROOT / "scripts")) from inference_queue import should_defer_background_work defer, reason = should_defer_background_work() return (not defer, reason) except Exception as exc: return False, f"defer_check_failed:{exc}" def _priority(item: dict) -> int: explicit = str(item.get("priority") or "").upper() if explicit in PRIORITY_ORDER: return PRIORITY_ORDER[explicit] text = str(item.get("request") or "") m = re.search(r"\b(P[0-2])\b", text, re.I) if m: return PRIORITY_ORDER.get(m.group(1).upper(), 9) return 5 def _junk_score(item: dict) -> int: """Higher = worse / deprioritize.""" req = str(item.get("request") or "") if "Acknowledged.**" in req and len(req) < 220: return 100 if req.strip().startswith("PHRONESIS UNIVERSAL"): return 90 return 0 def _pick_pending(inbox: dict) -> dict | None: items = [i for i in inbox.get("items") or [] if i.get("status") == "pending"] if not items: return None items.sort(key=lambda i: (_priority(i), _junk_score(i), str(i.get("ts") or ""))) return items[0] def _fresh_api_session_id(item_id: str) -> str: import uuid slug = re.sub(r"[^a-z0-9]", "", item_id.lower())[:8] or uuid.uuid4().hex[:8] return f"api-grok-inbox-{slug}-{uuid.uuid4().hex[:8]}" def _sharpen_prompt(request_text: str) -> str: """Add canonical paths when task is vague.""" base = request_text.strip() hints: list[str] = [] low = base.lower() if "sandbox" in low or "role-play" in low or "roleplay" in low: hints.append("read_file: D:\\PhronesisVault\\Roleplay-Sandbox\\README.md") hints.append("read_file: D:\\PhronesisVault\\Operations\\RP-Image-Pipeline-Master-2026-07-04.md") hints.append("write_file append findings to D:\\PhronesisVault\\Roleplay-Sandbox\\runtime\\sandbox-isolation-notes.md") if "comfy" in low or "image gen" in low or "pony" in low: hints.append("read_file: D:\\HermesData\\state\\rp-batch-state.json (if exists)") hints.append("terminal: Get-Process *comfy* -ErrorAction SilentlyContinue") if "whatsapp" in low: hints.append("search_files pattern=whatsapp path=D:\\HermesData") hints.append("read_file: D:\\HermesData\\config.yaml (discord/whatsapp section)") if "master plan" in low or "grok-hermes" in low: hints.append("read_file: D:\\PhronesisVault\\docs\\agent-coordination\\GROK-HERMES-MASTER-PLAN.md") if not hints: hints.append("read_file: D:\\PhronesisVault\\docs\\agent-coordination\\GROK-HERMES-MASTER-PLAN.md (6)") hint_block = "\n".join(f"- {h}" for h in hints[:6]) return ( f"{base}\n\n" f"[Grok Build sharpened paths]\n{hint_block}\n" "Use tool_calls. No narration." ) def _call_hermes(prompt: str, session_key: str, session_id: str) -> tuple[str, str]: payload = { "model": MODEL, "messages": [ {"role": "system", "content": CONSUMER_SYSTEM}, {"role": "user", "content": prompt}, ], "tool_choice": "required", } req = urllib.request.Request( GATEWAY, data=json.dumps(payload).encode("utf-8"), headers={ "Authorization": f"Bearer {_api_key()}", "Content-Type": "application/json", "X-Hermes-Session-Key": session_key, "X-Hermes-Session-Id": session_id, }, method="POST", ) try: with urllib.request.urlopen(req, timeout=600) as resp: data = json.loads(resp.read().decode("utf-8")) resolved = ( data.get("session_id") or resp.headers.get("X-Hermes-Session-Id") or session_id ) except urllib.error.HTTPError as exc: detail = exc.read().decode("utf-8", errors="replace")[:400] raise RuntimeError(f"gateway {exc.code}: {detail}") from exc choices = data.get("choices") or [] content = "" if choices: content = ((choices[0].get("message") or {}).get("content") or "").strip() return content, str(resolved) def _tool_turns_for_session(session_id: str, *, timeout_sec: float = 180.0) -> int: if not AGENT_LOG.is_file(): return 0 deadline = time.time() + timeout_sec pat = re.compile( rf"\[{re.escape(session_id)}\][^\n]*Turn ended:[^\n]*tool_turns=(\d+)" ) while time.time() < deadline: tail = AGENT_LOG.read_text(encoding="utf-8", errors="replace")[-120_000:] hits = [int(m) for m in pat.findall(tail)] if hits: return max(hits) time.sleep(1.0) return 0 def _maybe_restart_proxy() -> None: if not PROXY_RESTART.is_file(): return try: subprocess.run( [ "powershell", "-NoProfile", "-ExecutionPolicy", "Bypass", "-File", str(PROXY_RESTART), "-Force", ], capture_output=True, timeout=90, cwd=str(ROOT), ) except Exception: pass def _discord_token() -> str: sys.path.insert(0, str(ROOT / "hermes-agent")) from hermes_cli.config import get_env_value tok = (get_env_value("DISCORD_BOT_TOKEN") or "").strip() return tok.split(" #", 1)[0].strip() def _post_lane_c(thread_id: str, text: str) -> None: token = _discord_token() body = json.dumps({"content": text[:2000]}).encode("utf-8") req = urllib.request.Request( f"{DISCORD_API}/channels/{thread_id}/messages", data=body, headers={ "Authorization": f"Bot {token}", "Content-Type": "application/json", "User-Agent": "GrokInboxConsumer/1.0", }, method="POST", ) with urllib.request.urlopen(req, timeout=30): pass def process_one(*, dry_run: bool = False) -> dict: _load_env() inbox = _load_json(INBOX_FILE, {"items": []}) item = _pick_pending(inbox) if not item: return {"action": "idle", "pending": 0} if not stack_green(): return {"action": "skip", "reason": "stack_not_green", "item_id": item.get("id")} allowed, queue_reason = inference_queue_allows_background() if not allowed: return { "action": "skip", "reason": f"inference_deferred:{queue_reason}", "item_id": item.get("id"), } item_id = str(item.get("id") or "") request_text = str(item.get("request") or "").strip() thread_id = str(item.get("thread_id") or _load_json(CONFIG_FILE, {}).get("thread_id") or "") if dry_run: return {"action": "dry_run", "item_id": item_id, "request": request_text[:200]} session_key = f"agent:main:api:grok-inbox:{item_id[:8]}" prompt = _sharpen_prompt(request_text) item["status"] = "running" item["started_at"] = _utc_now() _save_json(INBOX_FILE, inbox) err = "" content = "" tool_turns = 0 attempts = int(item.get("attempts") or 0) for attempt in range(MAX_RETRIES + 1): session_id = _fresh_api_session_id(f"{item_id}-a{attempt}") turn_prompt = prompt if attempt == 0 else prompt + RETRY_SUFFIX if attempt > 0: _maybe_restart_proxy() time.sleep(2) try: content, resolved_sid = _call_hermes(turn_prompt, session_key, session_id) tool_turns = _tool_turns_for_session(resolved_sid) item["hermes_session_id"] = resolved_sid if tool_turns >= 1: break except Exception as exc: err = str(exc) if attempt >= MAX_RETRIES: break attempts += 1 item["attempts"] = attempts ok = tool_turns >= 1 and not err item["status"] = "done" if ok else "failed" item["tool_turns"] = tool_turns item["hermes_reply"] = content[:1000] item["finished_at"] = _utc_now() if not ok: item["error"] = err or "tool_turns=0" item["retry_hint"] = "Grok: BRIDGE_OPS heal,restart_proxy then re-queue with D:\\ paths" _save_json(INBOX_FILE, inbox) consumer_state = _load_json(STATE_FILE, {}) consumer_state["last_item_id"] = item_id consumer_state["last_status"] = item["status"] consumer_state["last_at"] = _utc_now() consumer_state["last_tool_turns"] = tool_turns _save_json(STATE_FILE, consumer_state) if thread_id: emoji = "" if item["status"] == "done" else "" summary = content[:300] if content else (err or "no reply") try: _post_lane_c( thread_id, f"{emoji} **Hermes inbox** `{item_id[:8]}` {item['status']} (try {attempts})\n" f"tools={tool_turns} | {summary}", ) except Exception as post_exc: item["post_error"] = str(post_exc)[:200] _save_json(INBOX_FILE, inbox) return { "action": "processed", "item_id": item_id, "status": item["status"], "tool_turns": tool_turns, "error": err, "attempts": attempts, } def _release_drain_lock() -> None: try: DRAIN_LOCK.unlink(missing_ok=True) except OSError: pass def drain_all(*, max_items: int = MAX_DRAIN, dry_run: bool = False) -> list[dict]: results: list[dict] = [] try: for _ in range(max_items): result = process_one(dry_run=dry_run) results.append(result) if result.get("action") in ("idle", "skip"): break if dry_run: break finally: _release_drain_lock() return results def main() -> int: parser = argparse.ArgumentParser(description="Grok inbox consumer") parser.add_argument("--once", action="store_true") parser.add_argument("--drain-all", action="store_true", help="Process up to 5 pending items") parser.add_argument("--dry-run", action="store_true") args = parser.parse_args() if args.drain_all: results = drain_all(dry_run=args.dry_run) print(json.dumps({"action": "drain_all", "results": results}, default=str)) return 0 if all(r.get("status") != "failed" for r in results if r.get("action") == "processed") else 1 result = process_one(dry_run=args.dry_run) print(json.dumps(result, default=str)) if result.get("action") == "idle": return 0 if result.get("action") == "skip": return 0 return 0 if result.get("status") == "done" else 1 if __name__ == "__main__": raise SystemExit(main())